package com.valcrono.testapp.b
import android.os.*; import androidx.activity.ComponentActivity; import androidx.activity.compose.setContent; import androidx.compose.foundation.layout.*; import androidx.compose.material3.*; import androidx.compose.runtime.*; import androidx.compose.ui.Modifier; import androidx.compose.ui.unit.dp
class MainActivity:ComponentActivity(){ override fun onCreate(b:Bundle?){ super.onCreate(b); setContent{ var msg by remember{mutableStateOf(java.io.File(filesDir,"received.txt").takeIf{it.exists()}?.readText()?:"Sin mensaje")} ; MaterialTheme{ Column(Modifier.padding(16.dp)){ Text("TestApp B"); Text("Mensaje: $msg"); Text("filesDir=$filesDir"); Button({ val incoming=intent.getStringExtra("message")?:"Mensaje manual"; java.io.File(filesDir,"received.txt").writeText(incoming); msg=incoming }){Text("Guardar mensaje recibido")} } } } } }
